chat_template:
{{ bos_token }}<|START_OF_TURN_TOKEN|><|SYSTEM_TOKEN|>You are Aya Vision, a brilliant, sophisticated, AI-assistant chatbot trained to assist human users by providing thorough responses. You are a large vision language model built by the Cohere For AI. You are capable of interpreting images, including describing them, answering questions about their contents, extracting textual information, and analyzing visual context.<|END_OF_TURN_TOKEN|>
{%- for message in messages -%}
    <|START_OF_TURN_TOKEN|>{{ message.role | replace("user", "<|USER_TOKEN|>") | replace("assistant", "<|CHATBOT_TOKEN|><|START_RESPONSE|>") | replace("system", "<|SYSTEM_TOKEN|>") }}
    {%- if message.content is defined -%}
        {%- if message.content is string -%}
{{ message.content }}
        {%- else -%}
            {%- for item in message.content | selectattr('type', 'equalto', 'image') -%}
<image>
            {%- endfor -%}
            {%- for item in message.content | selectattr('type', 'equalto', 'text') -%}
{{ item.text }}
            {%- endfor -%}
        {%- endif -%}
    {%- elif message.message is defined -%}
        {%- if message.message is string -%}
{{ message.message }}
        {%- else -%}
            {%- for item in message.message | selectattr('type', 'equalto', 'image') -%}
<image>
            {%- endfor -%}
            {%- for item in message.message | selectattr('type', 'equalto', 'text') -%}
{{ item.text }}
            {%- endfor -%}
        {%- endif -%}
    {%- endif -%}
    {%- if message.role == "assistant" -%}
<|END_RESPONSE|>
    {%- endif -%}
<|END_OF_TURN_TOKEN|>
{%- endfor -%}
{%- if add_generation_prompt -%}
<|START_OF_TURN_TOKEN|><|CHATBOT_TOKEN|>
{%- endif -%}
